insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'フアモア', 'Hua Moa', 'hua-moa', 'ポリネシア', 'フアモアはポリネシアに関連する調理・デザート兼用タイプのバナナです。完熟で甘く未熟果は調理向きの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '完熟で甘く未熟果は調理向き。', 'しっかり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 中。', '用途: 調理・デザート兼用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'フアモアは「調理・デザート兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'ゴールドフィンガー', 'FHIA-01 Goldfinger', 'fhia-01-goldfinger', 'ホンジュラス育成', 'ゴールドフィンガーはホンジュラス育成に関連するデザートタイプのバナナです。甘酸っぱく病害に比較的強いの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '甘酸っぱく病害に比較的強い。', 'しっかり', 'フルーティー', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'ゴールドフィンガーは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'モナリザ', 'FHIA-02 Mona Lisa', 'fhia-02-mona-lisa', 'ホンジュラス育成', 'モナリザはホンジュラス育成に関連するデザートタイプのバナナです。甘みがあり病害耐性を意識した系統の品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '甘みがあり病害耐性を意識した系統。', 'なめらか', '軽い', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'モナリザは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
