insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'FHIA-18', 'FHIA-18', 'fhia-18', 'ホンジュラス育成', 'FHIA-18はホンジュラス育成に関連するデザートタイプのバナナです。甘酸っぱく家庭向きの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '甘酸っぱく家庭向き。', 'なめらか', '軽い芳香', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'FHIA-18は「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'ヤンガンビKm5', 'Yangambi Km5', 'yangambi-km5', 'コンゴ民主共和国', 'ヤンガンビKm5はコンゴ民主共和国に関連するデザートタイプのバナナです。甘みがあり耐病性で知られるの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '小ぶり。草姿: 中型。', '甘みがあり耐病性で知られる。', 'なめらか', '軽い', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'ヤンガンビKm5は「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'ローズバナナ', 'Rose', 'rose', '東南アジア', 'ローズバナナは東南アジアに関連するデザートタイプのバナナです。香りのよい甘さの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '小ぶり。草姿: 小型。', '香りのよい甘さ。', 'なめらか', '芳香', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'ローズバナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'レッドバナナ', 'Red banana', 'red-banana', '東南アジア・中南米', 'レッドバナナは東南アジア・中南米に関連するデザートタイプのバナナです。濃い甘みと独特の香りの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '濃い甘みと独特の香り。', 'ねっとり', '芳香', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'レッドバナナは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'ドワーフレッド', 'Dwarf Red', 'dwarf-red', 'レッド系', 'ドワーフレッドはレッド系に関連するデザートタイプのバナナです。赤皮系の濃い甘みの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 小型。', '赤皮系の濃い甘み。', 'ねっとり', '芳香', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'ドワーフレッドは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
